4	describe("MHPCO Claim Office - Quote Policy", () => {
5	  it("should calculate premium for single sword without modifiers", () => {
6	    const items = [{ type: "sword", baseCost: 100 }];
7	    expect(quotePolicy(items)).toBe(100);
8	  });
9	  it("should calculate premium for single amulet without modifiers", () => {
10	    const items = [{ type: "amulet", baseCost: 150 }];
11	    expect(quotePolicy(items)).toBe(150);
12	  });
13	  it("should calculate premium for single staff without modifiers", () => {
14	    const items = [{ type: "staff", baseCost: 200 }];
15	    expect(quotePolicy(items)).toBe(200);
16	  });
17	  it("should calculate premium for multiple different items", () => {
18	    const items = [
19	      { type: "sword", baseCost: 100 },
20	      { type: "amulet", baseCost: 150 },
21	      { type: "staff", baseCost: 200 }
22	    ];
23	    expect(quotePolicy(items)).toBe(450);
24	  });
25	  it("should apply cursed item surcharge", () => {
26	    const items = [{ type: "sword", baseCost: 100, cursed: true }];
27	    expect(quotePolicy(items)).toBe(110);
28	  });
29	  it("should apply high enchantment surcharge for enchantment level >= 5", () => {
30	    const items = [{ type: "sword", baseCost: 100, enchantment: 5 }];
31	    expect(quotePolicy(items)).toBe(120);
32	  });
33	  it("should apply loyalty discount for loyalty >= 2 years", () => {
34	    const items = [{ type: "sword", baseCost: 100 }];
35	    expect(quotePolicy(items, { years: 2 })).toBe(90);
36	  });
37	  it("should apply first insurance surcharge", () => {
38	    const items = [{ type: "sword", baseCost: 100 }];
39	    expect(quotePolicy(items)).toBe(111);
40	  });
41	  it("should apply follow-up contract discount", () => {
42	    const items = [{ type: "sword", baseCost: 100 }];
43	    expect(quotePolicy(items, { followUp: true })).toBe(95);
44	  });
45	  it("should add processing fee of 5G", () => {
46	    const items = [{ type: "sword", baseCost: 100 }];
47	    expect(quotePolicy(items)).toBe(116);
48	  });
49	  it("should round premiums up in MHPCO's favor", () => {
50	    const items = [{ type: "sword", baseCost: 100.5 }];
51	    expect(quotePolicy(items)).toBe(117);
52	  });
53	  it("should bundle 3 components into block at discounted rate", () => {
54	    const items = [
55	      { type: "sword", baseCost: 100 },
56	      { type: "amulet", baseCost: 150 },
57	      { type: "staff", baseCost: 200 }
58	    ];
59	    expect(quotePolicy(items)).toBe(385.05);
60	  });
61	  it("should apply multiple modifiers together", () => {
62	    const items = [{ type: "sword", baseCost: 100, cursed: true, enchantment: 5 }];
63	    expect(quotePolicy(items)).toBe(180);
64	  });
65	  it("should enforce policy cap at 2x total item value", () => {
66	    const items = [{ type: "sword", baseCost: 100 }];
67	    expect(quotePolicy(items)).toBe(200);
68	  });
69	  it("should throw error for unknown item type", () => {
70	    const items = [{ type: "unknown", baseCost: 100 }];
71	    expect(() => quotePolicy(items)).toThrow();
72	  });
73	});
74	
75	describe("MHPCO Claim Office - Process Claim", () => {
76	  it("should deduct 100G per damage event", () => {
77	    const policy = [{ type: "sword", baseCost: 100 }];
78	    const claims = [{ itemIndex: 0, damageAmount: 50 }];
79	    expect(processClaim(policy, claims)).toBe(50);
80	  });
81	  it("should process reimbursement for standard item damage", () => {
82	    const policy = [{ type: "sword", baseCost: 100 }];
83	    const claims = [{ itemIndex: 0, damageAmount: 50 }];
84	    expect(processClaim(policy, claims)).toBe(0);
