87	    const policy = [{ type: "sword", baseCost: 100, enchantment: 8 }];
88	    const claims = [{ itemIndex: 0, damageAmount: 50 }];
89	    expect(processClaim(policy, claims)).toBe(25);
90	  });
91	  it("should apply 100% reimbursement for dragon material items", () => {
92	    const policy = [{ type: "sword", baseCost: 100, dragonMaterial: true }];
93	    const claims = [{ itemIndex: 0, damageAmount: 50 }];
94	    expect(processClaim(policy, claims)).toBe(50);
95	  });
96	  it("should cap reimbursement at policy maximum", () => {
97	    const policy = [{ type: "sword", baseCost: 100, dragonMaterial: true }];
98	    const claims = [{ itemIndex: 0, damageAmount: 300 }];
99	    expect(processClaim(policy, claims)).toBe(200);
100	  });
101	  it("should process multiple damage events in single claim", () => {
102	    const policy = [
103	      { type: "sword", baseCost: 100, dragonMaterial: true },
104	      { type: "amulet", baseCost: 150, dragonMaterial: true }
105	    ];
106	    const claims = [
107	      { itemIndex: 0, damageAmount: 30 },
108	      { itemIndex: 1, damageAmount: 40 }
109	    ];
110	    expect(processClaim(policy, claims)).toBe(50);
