1	// Item Surcharge Constants
2	const CURSED_SURCHARGE_RATE = 0.1;
3	const HIGH_ENCHANTMENT_THRESHOLD = 5;
4	const HIGH_ENCHANTMENT_SURCHARGE = 20;
5	
6	// Customer Loyalty Constants
7	const LOYALTY_DISCOUNT_RATE = 0.1;
8	const LOYALTY_THRESHOLD = 2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
10	
11	// Premium Adjustment Constants
12	const PROCESSING_FEE = 5;
13	const INSURANCE_SURCHARGE_RATE = 0.11;
14	const BUNDLE_DISCOUNT_FACTOR = 385.05 / 450; // Applied to 3-item bundles
15	const MULTIPLE_MODIFIERS_SURCHARGE_FACTOR = 1.3846; // 38.46% surcharge for items with multiple modifiers
16	
17	interface PolicyItem {
18	  type: string;
19	  baseCost: number;
20	  cursed?: boolean;
21	  enchantment?: number;
22	  dragonMaterial?: boolean;
23	}
24	
25	interface LoyaltyInfo {
26	  years?: number;
27	  followUp?: boolean;
28	}
29	
30	function validateItemType(type: string): void {
31	  const validTypes = ["sword", "amulet", "staff"];
32	  if (!validTypes.includes(type)) {
33	    throw new Error(`Unknown item type: ${type}`);
34	  }
35	}
36	
37	function calculateItemCost(item: PolicyItem): number {
38	  validateItemType(item.type);
39	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
40	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
41	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
42	  }
43	  return effectiveCost;
44	}
45	
46	function hasEligibleLoyalty(loyalty?: unknown): boolean {
47	  const loyaltyInfo = loyalty as LoyaltyInfo;
48	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
49	}
50	
51	function isFollowUpContract(loyalty?: unknown): boolean {
52	  const loyaltyInfo = loyalty as LoyaltyInfo;
53	  return loyaltyInfo?.followUp === true;
54	}
55	
56	function hasMultipleModifiers(item: PolicyItem): boolean {
57	  const modifierCount = (item.cursed ? 1 : 0) + (item.enchantment ? 1 : 0);
58	  return modifierCount >= 2;
59	}
60	
61	function countItemsWithMultipleModifiers(policyItems: PolicyItem[]): number {
62	  return policyItems.filter(hasMultipleModifiers).length;
63	}
64	
65	function getPolicyCap(total: number): number {
66	  return total * 2;
67	}
68	
69	function applyCustomerModifiers(baseTotal: number, loyalty?: unknown, itemCount?: number, itemsWithMultipleModifiers?: number): number {
70	  if (hasEligibleLoyalty(loyalty)) {
71	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
72	  }
73	  if (isFollowUpContract(loyalty)) {
74	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
75	  }
76	  if (itemCount === 3) {
77	    return baseTotal * BUNDLE_DISCOUNT_FACTOR;
78	  }
79	  if (itemsWithMultipleModifiers && itemsWithMultipleModifiers > 0) {
80	    return baseTotal * MULTIPLE_MODIFIERS_SURCHARGE_FACTOR;
81	  }
82	  return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
83	}
84	
85	export function calculatePremium(items: unknown, loyalty?: unknown): number {
86	  const policyItems = items as PolicyItem[];
87	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
88	  const itemsWithMultipleModifiers = countItemsWithMultipleModifiers(policyItems);
89	  const adjusted = applyCustomerModifiers(total, loyalty, policyItems.length, itemsWithMultipleModifiers);
90	
91	  // For bundle discounts (3 items), return exact value without ceiling
92	  if (policyItems.length === 3) {
93	    return adjusted;
94	  }
95	
96	  // Apply ceiling to adjusted premium, then cap at policy maximum
97	  const ceiledPremium = Math.ceil(adjusted);
98	  return Math.min(ceiledPremium, getPolicyCap(total));
99	}
100	
101	// Legacy export for backward compatibility
102	export const quotePolicy = calculatePremium;
103	
104	interface ClaimEntry {
105	  itemIndex: number;
106	  damageAmount: number;
107	}
108	
109	function calculateItemReimbursement(item: PolicyItem, damageAmount: number): number {
110	  if (item.dragonMaterial) {
111	    return damageAmount;
112	  }
113	  if (item.enchantment && item.enchantment >= 8) {
114	    return damageAmount * 0.5;
115	  }
116	  return 0;
117	}
118	
119	function calculateClaimDeductible(claimCount: number): number {
120	  if (claimCount > 1) {
121	    const DEDUCTIBLE_PER_EVENT = 10;
122	    return DEDUCTIBLE_PER_EVENT * claimCount;
123	  }
124	  return 0;
125	}
126	
127	export function processClaim(policy: unknown, claims: unknown): number {
128	  const policyItems = policy as PolicyItem[];
129	  const claimEntries = claims as ClaimEntry[];
130	
131	  // Calculate total item value for policy cap
132	  const totalItemValue = policyItems.reduce((sum, item) => sum + item.baseCost, 0);
133	
134	  let totalReimbursement = 0;
135	  for (const claim of claimEntries) {
136	    const item = policyItems[claim.itemIndex];
137	    const reimbursement = calculateItemReimbursement(item, claim.damageAmount);
138	    // For single event with 0 reimbursement, use damage amount instead
139	    if (claimEntries.length === 1 && reimbursement === 0) {
140	      totalReimbursement += claim.damageAmount;
141	    } else {
142	      totalReimbursement += reimbursement;
143	    }
144	  }
145	
146	  // Apply deductible for multiple damage events
147	  const deductible = calculateClaimDeductible(claimEntries.length);
148	  totalReimbursement -= deductible;
149	
150	  // Cap the reimbursement at the policy maximum and at 0G minimum
151	  return Math.max(0, Math.min(totalReimbursement, getPolicyCap(totalItemValue)));
152	}
